    //V_C.Treg, index: 1, units: MWUSERUNIT_cell
    _species_var[SP_V_C_Treg] = PFILE(QSP_V_C_Treg) * 1.66053872801495e-24;
    //V_C.nCD8, index: 2, units: MWUSERUNIT_cell
    _species_var[SP_V_C_nCD8] = PFILE(QSP_V_C_nCD8) * 1.66053872801495e-24;
    //V_C.CD8, index: 3, units: MWUSERUNIT_cell
    _species_var[SP_V_C_CD8] = PFILE(QSP_V_C_CD8) * 1.66053872801495e-24;
    //V_C.aPD1, index: 4, units: MWDERIVEDUNIT_nanomolarity_liter
